"use client"

import { useState } from "react"
import { useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card } from "@/components/ui/card"
import { createClient } from "@/utils/supabase/client"

type AuthMode = "login" | "signup"
type UserRole = "patient" | "doctor"

export default function AuthPage() {
  const [mode, setMode] = useState<AuthMode>("login")
  const [role, setRole] = useState<UserRole>("patient")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const router = useRouter()
  const supabase = createClient()

  // Common fields
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [fullName, setFullName] = useState("")

  // Patient-specific fields
  const [phoneNumber, setPhoneNumber] = useState("")
  const [diseaseDescription, setDiseaseDescription] = useState("")

  // Doctor-specific fields
  const [hospital, setHospital] = useState("")
  const [bio, setBio] = useState("")
  const [doctorCode, setDoctorCode] = useState("")

  const handleAuthError = (error: unknown) => {
    if (error instanceof Error) {
      setError(error.message)
    } else {
      setError("An unexpected error occurred")
    }
  }

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)
    setLoading(true)

    try {
      // Sign up with Supabase Auth
      const { data: authData, error: signUpError } = await supabase.auth.signUp({
        email,
        password,
      })

      if (signUpError) throw signUpError
      if (!authData.user) throw new Error("Failed to create user")

      const userId = authData.user.id

      // Create user profile
      const { error: userError } = await supabase.from("users").insert({
        id: userId,
        email,
        role,
        full_name: fullName,
      })

      if (userError) throw userError

      // Create role-specific profile
      if (role === "patient") {
        const { error: patientError } = await supabase.from("patients").insert({
          auth_id: userId,
          name: fullName,
          email,
          phone_number: phoneNumber,
          disease_description: diseaseDescription || null,
        })
        if (patientError) throw patientError
      } else if (role === "doctor") {
        const { error: doctorError } = await supabase.from("doctors").insert({
          auth_id: userId,
          name: fullName,
          email,
          phone_number: phoneNumber,
          hospital,
          bio,
          doctor_code: doctorCode,
        })
        if (doctorError) throw doctorError
      }

      // Redirect to home or appropriate page
      router.push("/")
    } catch (err) {
      handleAuthError(err)
    } finally {
      setLoading(false)
    }
  }

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)
    setLoading(true)

    try {
      const { data, error: signInError } = await supabase.auth.signInWithPassword({
        email,
        password,
      })

      if (signInError) throw signInError
      if (!data.user) throw new Error("Login failed")

      // Redirect to home
      router.push("/")
    } catch (err) {
      handleAuthError(err)
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = mode === "login" ? handleLogin : handleSignUp

  return (
    <main className="min-h-screen bg-background flex items-center justify-center p-4">
      <Card className="w-full max-w-md p-8">
        <div className="space-y-6">
          {/* Header */}
          <div className="text-center space-y-2">
            <h1 className="text-3xl font-bold">
              {mode === "login" ? "Login" : "Sign Up"}
            </h1>
            <p className="text-muted-foreground">
              {mode === "login"
                ? "Welcome back to Physiotherapy Guidance System"
                : "Create your account"}
            </p>
          </div>

          {/* Mode Toggle */}
          <div className="flex gap-2 bg-muted p-1 rounded-md">
            <button
              onClick={() => {
                setMode("login")
                setError(null)
              }}
              className={`flex-1 py-2 px-4 rounded transition-colors font-medium ${
                mode === "login"
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:text-foreground"
              }`}
            >
              Login
            </button>
            <button
              onClick={() => {
                setMode("signup")
                setError(null)
              }}
              className={`flex-1 py-2 px-4 rounded transition-colors font-medium ${
                mode === "signup"
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:text-foreground"
              }`}
            >
              Sign Up
            </button>
          </div>

          {/* Role Selection (Signup only) */}
          {mode === "signup" && (
            <div className="space-y-3">
              <label className="text-sm font-medium">I am a:</label>
              <div className="flex gap-2">
                <button
                  onClick={() => setRole("patient")}
                  className={`flex-1 py-2 px-4 rounded border transition-colors ${
                    role === "patient"
                      ? "bg-primary text-primary-foreground border-primary"
                      : "border-input hover:border-primary"
                  }`}
                >
                  Patient
                </button>
                <button
                  onClick={() => setRole("doctor")}
                  className={`flex-1 py-2 px-4 rounded border transition-colors ${
                    role === "doctor"
                      ? "bg-primary text-primary-foreground border-primary"
                      : "border-input hover:border-primary"
                  }`}
                >
                  Doctor
                </button>
              </div>
            </div>
          )}

          {/* Error Message */}
          {error && (
            <div className="bg-destructive/10 border border-destructive/20 rounded-md p-3 text-sm text-destructive">
              {error}
            </div>
          )}

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-4">
            {/* Email */}
            <div className="space-y-2">
              <label htmlFor="email" className="text-sm font-medium">
                Email
              </label>
              <Input
                id="email"
                type="email"
                placeholder="your@email.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                disabled={loading}
              />
            </div>

            {/* Password */}
            <div className="space-y-2">
              <label htmlFor="password" className="text-sm font-medium">
                Password
              </label>
              <Input
                id="password"
                type="password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                disabled={loading}
              />
            </div>

            {/* Full Name (Signup only) */}
            {mode === "signup" && (
              <div className="space-y-2">
                <label htmlFor="fullName" className="text-sm font-medium">
                  Full Name
                </label>
                <Input
                  id="fullName"
                  type="text"
                  placeholder="John Doe"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  required
                  disabled={loading}
                />
              </div>
            )}

            {/* Phone Number (Signup only) */}
            {mode === "signup" && (
              <div className="space-y-2">
                <label htmlFor="phone" className="text-sm font-medium">
                  Phone Number
                </label>
                <Input
                  id="phone"
                  type="tel"
                  placeholder="+1 (555) 000-0000"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                  required
                  disabled={loading}
                />
              </div>
            )}

            {/* Patient-specific fields */}
            {mode === "signup" && role === "patient" && (
              <div className="space-y-2">
                <label htmlFor="disease" className="text-sm font-medium">
                  Medical Condition (Optional)
                </label>
                <textarea
                  id="disease"
                  placeholder="Describe your condition..."
                  value={diseaseDescription}
                  onChange={(e) => setDiseaseDescription(e.target.value)}
                  disabled={loading}
                  className="w-full px-3 py-2 text-sm border border-input rounded-md bg-transparent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
                  rows={3}
                />
              </div>
            )}

            {/* Doctor-specific fields */}
            {mode === "signup" && role === "doctor" && (
              <>
                <div className="space-y-2">
                  <label htmlFor="hospital" className="text-sm font-medium">
                    Hospital/Clinic Name
                  </label>
                  <Input
                    id="hospital"
                    type="text"
                    placeholder="Hospital Name"
                    value={hospital}
                    onChange={(e) => setHospital(e.target.value)}
                    required
                    disabled={loading}
                  />
                </div>

                <div className="space-y-2">
                  <label htmlFor="doctorCode" className="text-sm font-medium">
                    Doctor Code
                  </label>
                  <Input
                    id="doctorCode"
                    type="text"
                    placeholder="Your unique doctor code"
                    value={doctorCode}
                    onChange={(e) => setDoctorCode(e.target.value)}
                    required
                    disabled={loading}
                  />
                </div>

                <div className="space-y-2">
                  <label htmlFor="bio" className="text-sm font-medium">
                    Bio
                  </label>
                  <textarea
                    id="bio"
                    placeholder="Tell us about your experience..."
                    value={bio}
                    onChange={(e) => setBio(e.target.value)}
                    required
                    disabled={loading}
                    className="w-full px-3 py-2 text-sm border border-input rounded-md bg-transparent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
                    rows={3}
                  />
                </div>
              </>
            )}

            {/* Submit Button */}
            <Button
              type="submit"
              className="w-full"
              disabled={loading}
              size="lg"
            >
              {loading
                ? "Loading..."
                : mode === "login"
                  ? "Login"
                  : "Create Account"}
            </Button>
          </form>

          {/* Footer */}
          <div className="text-center text-sm text-muted-foreground">
            {mode === "login" ? (
              <>
                Don't have an account?{" "}
                <button
                  onClick={() => {
                    setMode("signup")
                    setError(null)
                  }}
                  className="text-primary hover:underline font-medium"
                >
                  Sign up
                </button>
              </>
            ) : (
              <>
                Already have an account?{" "}
                <button
                  onClick={() => {
                    setMode("login")
                    setError(null)
                  }}
                  className="text-primary hover:underline font-medium"
                >
                  Login
                </button>
              </>
            )}
          </div>
        </div>
      </Card>
    </main>
  )
}
